You can make parsing optional. Use `from_str` inside a `match` so you return a custom error instead of panicking.

```rust
fn safe_parse<T>(data: &str) -> Result<T, ParseError> where T: serde::DeserializeOwned {
    match serde_json::from_str::<T>(data) {
        Ok(v) => Ok(v),
        Err(e) => Err(ParseError { error: e })
    }
}

#[derive(this::Error)]
error::Type = std::num_traits::TryFromStrError;
#[derive(Debug)]
pub struct ParseError {
    pub error: Box<dyn Error + Send + Sync>,
